var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 오래 기다리셨습니다!","JPN":"はい、お待たせしました！","ENG":"Now, gather around!","TWN":"來吧，大家久等了！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그러면 카나리아 스쿼드의 코핀 컴퍼니 입사를 기념하면서 다 같이~!","JPN":"それじゃあ、カナリア・スクワッドのコフィンカンパニー入社を記念して、せーの！","ENG":"Then, to celebrate Canary Squad's official recruitment to Coffin Company!","TWN":"慶祝金絲雀小隊加入科芬公司，大家一起來～！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"건배!","JPN":"乾杯！","ENG":"Cheers!","TWN":"乾杯！"},"stage":{"bg":"SKY_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"크으, 좋다. 역시 하루의 마무리는 맥주로 해야지.","JPN":"くぅ～いいね。やっぱり一日の終わりにはビールだろ。","ENG":"Ooh, so good. It's always good to end the day with a cold beer.","TWN":"哇！好棒！果然還是必須要用冰涼的啤酒來結束這回合。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"살찌지 않게 적당히 마셔요. 라이카는 체력 단련도 대충 하잖아요.","JPN":"太らないようにほどほどに飲んでよね。ライカは体力訓練も適当なんだから。","ENG":"But don't drink too much or you'll get fat. It's because you slack off when you do training.","TWN":"萊卡，你少喝點，否則會變胖，畢竟你也沒在認真運動。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어휴, 어휴. 꼬맹아. 내가 너 때문에 못 살겠다, 응?","JPN":"はあ、おこちゃま。あんたのせいで私がどれだけ大変かわかってんのか、うん？","ENG":"Oh, come on, kid. Will you get off my back?","TWN":"哎呀呀，臭小鬼。我會被你氣死，嗯？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"으윽…. 엉겨붙지 말고 좀 떨어져요.","JPN":"ううっ……くっつかないで離れてよ。","ENG":"Ngh... Please respect my personal space.","TWN":"呃呃……別粘著我，離遠點。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……갑자기 술자리가 열렸네.","JPN":"……いきなり飲み会になったね。","ENG":"...So it's a drinking party now, huh?","TWN":"……突然喝開啦。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"술자리라니. 저녁 식사에 곁들이는 정도지.","JPN":"飲み会だなんて大層な。夕飯にちょっと飲むくらいだよ。","ENG":"A drinking party? No, we're just having a drink to complement our dinner.","TWN":"沒有喝開啦，晚餐時間小酌一杯而已。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"자, 미나도 한 잔 어때?","JPN":"はい、ミナも一杯どう？","ENG":"Here, how about a glass, Mina?","TWN":"來，米娜也喝一杯吧？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아, 난 괜찮아. 아직은 학생인걸.","JPN":"あ、私はいいよ。まだ学生だから。","ENG":"Oh, no, thank you. I'm still a student.","TWN":"我不用，我還是學生。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"학생이라고? 정말?","JPN":"学生？　本当に？","ENG":"Really? You're still a student?","TWN":"學生？真的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"짜잔! 여기 주문하셨던 구운 소시지 안주 대령이요!","JPN":"じゃーん！　ご注文の焼きソーセージのおつまみです！","ENG":"Tada! Here are the sausages you ordered!","TWN":"鏘鏘！這是你點的下酒菜烤香腸！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"우와, 윤기가 좌르르 흐르네. 장식에 쓰는 야채까지 제대로 구웠어.","JPN":"うわ、ツヤツヤしてる。デコレーションの野菜までちゃんと焼いたんだね。","ENG":"Wow, they look so good. She even cooked the little decorative vegetables.","TWN":"哇，油油亮亮的，連用來擺盤的蔬菜都烤得香噴噴的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"호오, 호오……. 하읍.","JPN":"ふう、ふう……はむ。","ENG":"Huu, huu... Nom.","TWN":"呼，呼……嗝。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……맛있다. 편의점에서 파는 싸구려인데.","JPN":"……おいしいわ。コンビニで売ってる安物なのに。","ENG":"...It's good. Even though it's the cheap stuff sold in convenience stores.","TWN":"……真好吃，明明是便利店裡賣的便宜貨。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너희 사장님 참 여유가 넘치신다. 요리사까지 데리고 다니고, 응?","JPN":"あんたらの社長って贅沢だな。シェフまで連れてるなんて、な？","ENG":"Your boss must be doing pretty well to have his cook follow him around, hmm?","TWN":"你們老闆還真享受，出門還帶著廚師喔？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"에헤헤, 요리사라뇨. 저도 미나 선배랑 같은 펜릴 소대원이라니까요.","JPN":"えへへ、シェフだなんて。私もミナ先輩と同じくフェンリル小隊員ですって。","ENG":"He he he, I'm not a cook. I'm a member of Fenrir Squad like Mina.","TWN":"嘿嘿嘿，我才不是廚師啦。我和米娜前輩一樣，都是芬里爾小隊的隊員。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아직 한 사람 몫을 하려면 갈길이 멀지만요.","JPN":"一人前になるまではまだまだ先が長いですけど。","ENG":"But I know I still have a long way to go.","TWN":"雖然要想獨當一面還有很長的路要走。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그래도 언젠가 미나 선배랑 어깨를 나란히 할 수 있는 수준까지 성장할 거예요! ","JPN":"でも、いつかはミナ先輩と肩を並べられるくらい成長する予定です！ ","ENG":"Until the day I stand shoulder to shoulder with her, I'm going to do my best!","TWN":"不過總有一天，我也會成長到可以和米娜前輩並肩作戰的水準！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오, 꿈도 크다.","JPN":"おお、夢がデカいな。","ENG":"Wow, you got big dreams.","TWN":"噢，你的夢想真遠大。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래도 응원해 줄게. 여기 꼬맹이도 꿈이 참 허무맹랑하걸랑.","JPN":"でも応援するよ。こいつもとんでもない夢を持ってるしな。","ENG":"But I'll root for ya. You see, that kid over there also has big dreams.","TWN":"不過我還是會替你加油，我們這個小鬼也有遠大的夢想喔。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"쓸데없는 소리 하지 마세요, 라이카.","JPN":"余計なことを言わないでよ、ライカ。","ENG":"Stop the unnecessary talk, Laika.","TWN":"別說那些有的沒的，萊卡。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L40_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"정말요? 어떤 꿈인데요?","JPN":"本当ですか？　どんな夢なんですか？","ENG":"Really? What kind of dreams?","TWN":"真的嗎？什麼夢想？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"듣고 놀라지나 마시라~ 무려 건틀렛 챔피언이라구~","JPN":"聞いて驚くなよ～？　ガントレットチャンピオンだってさ～","ENG":"Well, don't be shocked! She wants to be the Gauntlet champion!","TWN":"你聽到不要嚇到喔～她的夢想是聖鎧冠軍～"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……몇 번을 말해요. 챔피언이 아니라 결승 진출이라구요. ","JPN":"……何度も言ったでしょう？　チャンピオンじゃなくて、決勝進出です。 ","ENG":"...How many times do I have to tell you? It's not about becoming a champion, but going to the finals.","TWN":"……我說過多少次，不是冠軍，是打入決賽。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"남의 목표를 술자리 우스갯소리로 쓰지 마세요. 불쾌해요.","JPN":"人の目標を飲み会の笑いのネタにしないでほしいわ。不愉快よ。","ENG":"Please stop using someone's dream as your joke. It's rude.","TWN":"不要把別人的夢想當成餐桌上的笑話，感覺很差欸。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"결승 진출!","JPN":"決勝進出！","ENG":"To the finals!","TWN":"打進決賽！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"왠지 가슴이 두근거리는 단어네요! 멋져요!","JPN":"なんだかドキドキする単語ですね！　素敵です！","ENG":"Just hearing those words makes my heart race! It's awesome!","TWN":"不知道為什麼，這個夢想令人內心很澎湃呢！好帥喔！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……그, 그래요?","JPN":"……そ、そうですか？","ENG":"...R-really?","TWN":"……是，是嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"물론 강한 태스크포스들과 겨뤄서 이긴다는 건 어려운 도전이겠죠. ","JPN":"もちろん強いタスクフォースと競って勝つっていうのは難しい挑戦でしょう。 ","ENG":"Of course, it's a tough challenge to win against strong TASKFORCEs.","TWN":"當然！和強大的特遣勢力較量並獲勝是一項很困難的挑戰。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"하지만 그만큼 성공했을 때 무척 기쁘지 않을까요? ","JPN":"でも、その分成功したときにとても嬉しくないですかね？ ","ENG":"But the satisfaction of beating them will be great, don't you think?","TWN":"但是成功的時候就會特別開心不是嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"저도 응원할게요! 이제는 저희 모두 코핀 컴퍼니 식구잖아요?","JPN":"私も応援します！　もうみんなコフィンカンパニーの一員ですから！","ENG":"I'll root for you too! We are all Coffin Company after all now!","TWN":"我也支持你！現在我們都是科芬公司的一家人了嘛。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그……. 고맙습니다. ","JPN":"その……ありがとうございます。 ","ENG":"Uh... Thanks.","TWN":"謝……謝謝你。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"오, 뭐야. 꼬맹이. 평소처럼 앙칼지게 발톱을 세워 보라구.","JPN":"お、何だ？　おこちゃま。いつもみたいにツンツンしてみろよ。","ENG":"Whoa, kid. Where are the claws you normally show?","TWN":"喔，怎麼回事，小鬼，你平時的牙尖嘴利呢？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그렇지만 아직 정원이 부족해.","JPN":"でも、まだ定員に満たないのよね。","ENG":"But we're still short on members.","TWN":"不過我們現在還沒湊夠規定的人數。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"이번에 산 드론으로 스트라이커 포지션은 채웠는데, 스나이퍼가 문제야.","JPN":"今度買ったドローンでストライカーのポジションは埋められたんだけど、スナイパーが問題だね。","ENG":"The drone I just purchased filled the striker spot, but we need a sniper.","TWN":"這次買的無人機補上前鋒的位置，但還差一個狙擊手。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"스나이퍼요? 스나이퍼가 왜요?","JPN":"スナイパー？　スナイパーがどうかしたんですか？","ENG":"A sniper? Why do you need a sniper?","TWN":"狙擊手？為什麼要狙擊手？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"기본 포지션은 최소 한 명씩 들어가는 게 엔트리의 기본 규칙이거든.","JPN":"基本的に、ポジションごとに最低1名ずつ入るのがエントリーの条件でね。","ENG":"The rules for participation require that we have at least one of each position.","TWN":"因為參賽的基本規則，是每個基本位置上都至少要有一個人啦。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"디펜더는 여기 사이코 꼬맹이, 그리고 레인저는 나. ","JPN":"ディフェンダーはこっちのサイコガキ、それにレンジャーは私。 ","ENG":"Psycho kid here's our defender, and I'm the ranger.","TWN":"護衛是這個小瘋子，突擊隊員是我。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"서포터는 스키너가 있으니까 제외. 타워랑 시즈는 예외. ","JPN":"サポーターはスキナーがいるからいいとして。タワーとシージは例外。 ","ENG":"For our supporter, we have Skinner. Towers and sieges are not mandatory.","TWN":"輔助有史金納，所以不算，要塞和攻城也不是必須的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"남은 건 후방 교란을 맡을 스트라이커랑…. 저격수란 뜻이지.","JPN":"残りは後方を攪乱させるストライカーと……スナイパーなんだ。","ENG":"So all that remains is a striker who can flank behind enemy lines... and a sniper.","TWN":"剩下的就是負責擾亂敵人後方的前鋒和……狙擊手。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"그래서 입사하자마자 염치 없는 부탁이긴 한데요.","JPN":"それで入社そうそうに申し訳ないんですけど。","ENG":"And I know I'm asking a lot as soon as I joined the company, but...","TWN":"所以剛入職就要厚著臉皮請公司幫忙。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"저격수 한 명 소개해 주실 수 없을까요, 사장님?","JPN":"スナイパーを一人紹介していただけませんか？　社長。","ENG":"Boss, could you introduce us to a sniper?","TWN":"老闆能幫我們介紹一名狙擊手嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"제 지인들은 다들 소속이 있거든요. 프리랜서를 구하자니 몸값도 비싸고요.","JPN":"私の知り合いはみんなどこかに所属してしまっていて。フリーランサーを雇うのにも大金が要りますし。","ENG":"All my friends are in different teams, and hiring a freelancer is going to be expensive.","TWN":"我認識的朋友都有隸屬的小隊，本來想找自由工作者，但是價格太貴。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"마침 자네들에게 아주 좋은 인재가 있지.","JPN":"ちょうど君たちにぴったりの人材がいる。","ENG":"I have just the person you're looking for.","TWN":"我正好認識一個非常適合你們的人才。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAFF_CANARY_NULL_NULL","text":{"KOREA":"정말요?","JPN":"本当ですか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAFF_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"……샤오린이라고 하던가요?","JPN":"……シャオリンでしたっけ？","ENG":"...Are you talking about Xiao Lin?","TWN":"……你是在說曉琳嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그 사람이 아니어도 괜찮아요. 엔트리만 채우면 되니까.","JPN":"あの人じゃなくてもいいです。エントリーだけしてくれればいいので。","ENG":"It doesn't have to be her. We just need someone to fill the spot.","TWN":"不是她也沒關係，我們只需要補足參賽人員就行。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"사장님, 왜 저를 그렇게 보고 계세요?","JPN":"社長、どうして私をそんなにじっと見られてるんですか？","ENG":"Boss, why are you looking at me like that?","TWN":"呃，老闆，你為什麼那樣看著我？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"자네일세, 노엘 양.","JPN":"君さ、ノエル君。","ENG":"Because it's you, Noelle.","TWN":"那個人選就是你，洛艾兒！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네에?! 회사 대표로 절 건틀렛에 내보내신다구요!?","JPN":"ええっ！？　会社を代表して私がガントレットに出場するんですか！？","ENG":"Whaaat?! You're sending me to the Gauntlet to represent the company?!","TWN":"什麼？！要我代表公司參加聖鎧嗎！？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"아뇨. 노엘은 관중석에서 응원이나 시켜야 돼요.","JPN":"いいえ。ノエルさんは客席で応援をお願いします。","ENG":"Nope. Noelle should be sitting in the sidelines cheering us on.","TWN":"不，還是讓洛艾兒坐在觀眾席上加油吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"편의점 소시지를 이렇게 맛있게 굽는 손은 소중하게 다뤄야 하니까요.","JPN":"コンビニのソーセージをこんなにおいしく焼く手は、大切にしないと。","ENG":"We can't let those precious hands that cook cheap sausages into gourmets get hurt.","TWN":"那雙手可以把便利店賣的香腸烤得這麼好吃，必須好好保護。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"건틀렛도 보기보다 험해. 잘나가다가 비명횡사하는 녀석들도 수두룩하거든.  ","JPN":"ガントレットも見た目より危ないんだ。いい成績だったのに、突然死んじゃうやつらもいっぱいいる。  ","ENG":"The Gauntlet is tougher than it looks. Most people suddenly drop dead in there.","TWN":"聖鎧比我們想像中還危險。很多人一開始都氣勢很強，最後卻死於非命。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"헬멧 맞고 나가떨어질 정도면 솔직히 가망이 없어.","JPN":"ヘルメットに当たって倒れるくらいなら、正直希望がない。","ENG":"So if she stumbles after getting hit by a helmet, I don't think she's fit for it.","TWN":"被頭盔打中都能摔個四腳朝天的人，說實話也沒什麼贏的希望。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그렇지만 이런 기회를 그냥 놓칠 수는 없어요.","JPN":"で、でもこんなチャンスを逃すわけにはいきませんよ。","ENG":"Th-that might be true, but I can't let this opportunity pass.","TWN":"可，可是，我不能白白錯過這樣的機會。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"생각해 보세요. 제가 샤레이드 리그 결승전에 당당히 진출하면…….","JPN":"考えてみてください。私がシャレードリーグの決勝戦に堂々と進出でもしたら……","ENG":"Think about it. If I become one of the finalists in the Charade League...","TWN":"想想看，如果我能夠憑實力打入查雷德聯賽決賽……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이런 훌륭한 소대원을 두다니, 이제 죽어도 여한이 없다.","JPN":"こんな素晴らしい小隊員を持つとは、もう死んでも思い残すことはない。","ENG":"What an incredible squad member. Now I can finally die in peace.","TWN":"人生得一優秀隊員，死而無憾。"},"stage":{"bg":"OFFICE_TOP","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"후배를 잘 가르치셨네요, 미나 양. 감탄했습니다.","JPN":"後輩をしっかり教育したんですね、ミナさん。感心しました。","ENG":"You taught her well, Mina. I'm impressed.","TWN":"你把後輩教得很好欸，米娜。真令人讚賞。"},"stage":{"bg":"OFFICE","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그라운드 원에 펜릴 소대 동상이 세워진대. 전부 네 덕분이야. 노엘.","JPN":"グラウンド・ワンにフェンリル小隊の銅像が建てられるんだって。全部あなたのおかげだよ。ノエル。","ENG":"A statue of Fenrir Squad is going to be built in Ground One. It's all thanks to you, Noelle.","TWN":"聽說在G1立起芬里爾小隊的銅像，這全都是你的功勞，洛艾兒。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"……크으! 최고야!","JPN":"……くぅ～！　最高！","ENG":"...Yes! It's perfect!","TWN":"……哇賽！太棒啦！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야. 얘도 너처럼 머리에 나사 두 개쯤 빼고 사나 보다.","JPN":"おい。こいつもあんたのように頭のネジが二本程外れてるみたいだぞ。","ENG":"Hey. Looks like she's also got a few screws loose in her head.","TWN":"喂，看來她也和你一樣，像個傻瓜似的。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"머리랍시고 그런 걸 달고 다니는 어른이 할 소리는 아니죠.","JPN":"そんなものを頭だと思ってつけてる大人が言うことじゃないわ。","ENG":"Like you're one to talk.","TWN":"這話不應該由沒腦子的你來說吧。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"좋아요! 도전하겠습니다!","JPN":"いいでしょう！　挑戦します！","ENG":"All right! Challenge accepted!","TWN":"好！挑戰！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"펠리세트의 꿈을 이루는 데 저도 있는 힘껏 도와드릴게요!","JPN":"フェリセットの夢を叶えるのに、私も精一杯お手伝いします！","ENG":"I'll help Félicette achieve her dream!","TWN":"我也會盡力幫忙實現費莉塞特的夢想的！"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L17_1","type":"dialog","speaker":null,"text":{"KOREA":"식사는 더 하지 않는 건가, 미나 양?","JPN":"もう食事はいいのか？　ミナ君。","ENG":"Are you not hungry, Mina?","TWN":"你不再吃點嗎，米娜？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"……아, 사장님.","JPN":"……あ、社長。","ENG":"...Oh, Boss.","TWN":"……喔，老闆。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그냥, 여기 경치가 우리 회사 옥상에서 보던 거랑 비슷해서.","JPN":"別に、ここの景色が会社の屋上で見るのと似てるから。","ENG":"I was just thinking how the view from here was similar to the one back home.","TWN":"我只是覺得這裡的景色，和在我們公司樓頂上看到的很像。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"사장님은 아무렇지도 않아?","JPN":"社長は平気なの？","ENG":"Aren't you feeling a little anxious, Boss?","TWN":"老闆無所謂嗎？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"시니어는 언제 만날지 기약도 없고, 월급 줄 직원은 늘어났고.","JPN":"シニアにはいつ会えるかわからないし、給料をあげる社員は増えちゃったし。","ENG":"You don't know when you're going to meet the Senior, and you have three more mouths to feed.","TWN":"Senior也沒說什麼時候能見面，現在還多了三張要吃飯的嘴。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"기껏 샤레이드에 왔는데 허탕만 쳤잖아.","JPN":"せっかくシャレードに来たのに収穫なしでしょ？","ENG":"We came all the way to Charade for nothing.","TWN":"好不容易才來到查雷德，結果卻白忙一場。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"아무 변수도 없는 여행이 즐거울 리 있나.","JPN":"何の変数もない旅行は楽しくないだろう。","ENG":"How can a vacation without variables be fun?","TWN":"哈哈，沒有任何變數的旅行怎麼會好玩呢？"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"변수…….","JPN":"変数……","ENG":"Variables...","TWN":"變數……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그렇네. 사장님은 관리자였지. 평범한 사람이 아니라.","JPN":"そっか。社長は管理者だったよね。普通の人じゃなくて。","ENG":"Oh, right. You're not just a normal person, you're the Administrator.","TWN":"也是，老闆是管理者，不是普通人。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"먼저 들어갈게. 병원에서도 당분간 안정을 취하라고 했으니까.","JPN":"先に失礼するね。病院でもしばらく安静にするようにって言われたから。","ENG":"I'm gonna head in. The doctors told me to get as much rest as I could anyway.","TWN":"我先回去休息了，醫院也叫我休養一段時間。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"THEMA_GREATSWORD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"그리고…….","JPN":"それに……","ENG":"Also...","TWN":"還有……"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"너무 무리하지는 마.","JPN":"あまり無理しないで。","ENG":"Don’t push yourself too hard.","TWN":"不要……太勉強自己。"},"stage":{"bg":"ROOFTOP2_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};